query ActressRankingPage($limit: Int!, $offset: Int, $filter: PPVActressRankingFilterInput!, $shouldGetBookmark: Boolean!, $shouldGetLegacyBookmark: Boolean!) {
  ppvActressRanking(limit: $limit, offset: $offset, filter: $filter) {
    items {
      id
      rank
      actress {
        id
        name
        imageUrl
        contentsCountOnSale
        latestContent {
          id
          title
          ... on PPVContentSummary {
            releaseStatus
            isExclusiveDelivery
            pricing {
              sale {
                id
                name
                __typename
              }
              __typename
            }
            __typename
          }
          __typename
        }
        isFavorite @include(if: $shouldGetBookmark)
        isBookmarked @include(if: $shouldGetLegacyBookmark)
        __typename
      }
      __typename
    }
    __typename
  }
}
